require "common.ui.window.GUICustomShopTab"
require "common.ui.window.GUICustomShopGoods"
require "common.ui.window.GUICurrency"

local UICustomShop = class("GUICustomShop", IGUILayout)

function UICustomShop:onLoad()
    self.curSelectTab = nil
    self.curSelectGoods = nil

    local llMain = self:getChildWindow("BedWarCustomShop-Main", GUIType.Layout)
    local size = llMain:GetPixelSize()
    local width = math.min((size.y / 574) * 1138, size.x)
    llMain:SetWidth({ 0, width })

    self.btnClose = self:getChildWindow("BedWarCustomShop-Close", GUIType.Button)

    local llMoney = self:getChildWindow("BedWarCustomShop-Money", GUIType.Layout)
    self.llCurrency = GUICurrency.new("BedWarCurrency.json")
    self.llCurrency:onDataChanged({ ItemId = 0, RealId = Define.Money.DIAMOND })
    llMoney:AddChildWindow(self.llCurrency.root)

    local tvTitleText = self:getChildWindow("BedWarCustomShop-Title-Text", GUIType.StaticText)
    tvTitleText:SetText(Lang:getString("bed.war.custom.shop"))

    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        self:hide(true)
    end)

    local btnCloseMask = self:getChildWindow("BedWarCustomShop-Close-Mask", GUIType.Button)
    btnCloseMask:registerEvent(GUIEvent.ButtonClick, function()
        self:hide(true)
    end)

    self.btnBuy = self:getChildWindow("BedWarCustomShop-Buy", GUIType.Button)
    self.btnBuy:registerEvent(GUIEvent.ButtonClick, function()
        self:onBuyClick()
    end)
    self.tvNoBuyText = self:getChildWindow("BedWarCustomShop-No-Buy-Text", GUIType.StaticText)

    self.llContent = self:getChildWindow("BedWarCustomShop-Content", GUIType.Layout)
    self.awPlayer1 = self:getChildWindow("BedWarCustomShop-Player1", GUIType.ActorWindow)
    self.awPlayer2 = self:getChildWindow("BedWarCustomShop-Player2", GUIType.ActorWindow)
    self.awPet1 = self:getChildWindow("BedWarCustomShop-Pet1", GUIType.ActorWindow)
    self.awPet2 = self:getChildWindow("BedWarCustomShop-Pet2", GUIType.ActorWindow)

    local llSlideBlock = self:getChildWindow("BedWarCustomShop-Slide-Block")
    llSlideBlock:registerMouseEvent(GUIEvent.TouchDown, function(events)
        self.awPlayer1:TouchDown(events.position)
        self.awPlayer2:TouchDown(events.position)
        self.awPet1:TouchDown(events.position)
        self.awPet2:TouchDown(events.position)
    end)
    llSlideBlock:registerMouseEvent(GUIEvent.TouchMove, function(events)
        self.awPlayer1:TouchMove(events.position)
        self.awPlayer2:TouchMove(events.position)
        self.awPet1:TouchMove(events.position)
        self.awPet2:TouchMove(events.position)
    end)

    self:initGoodsListUI()
    self:initTabs()
    self:showModelType(CustomShopModelType.Small)
end

function UICustomShop:initGoodsListUI()
    local llGoodsList = self:getChildWindow("BedWarCustomShop-GoodsList")
    self.gvGoodsList = IGUIGridView.new("BedWarCustomShop-Goods-List", llGoodsList)
    self.gvGoodsList.root:SetClipChild(false)
    self.gvGoodsList:setConfig(8, 8, 2)
    self.goodsAdapter = require("common.ui.adapter.CustomShopGoodsAdapter").new()
    local contentWidth = self.gvGoodsList:getWidth() - 18
    local itemWidth = contentWidth / 2
    local itemHeight = (itemWidth / 130) * 155
    self.goodsAdapter:setItemSize(itemWidth, itemHeight)
    self.gvGoodsList:setAdapter(self.goodsAdapter)
end

function UICustomShop:isShowAnim()
    return false
end

function UICustomShop:show(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.openStore)
    end
    self.super.show(self)
end

function UICustomShop:hide(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.closeStore)
    end
    self.super.hide(self)
end

function UICustomShop:onTick()
    self.llCurrency:onTick()
end

local function setDefaultCloth()
    local map = { "custom_hair", "clothes_tops", "clothes_pants", "custom_shoes" }
    local inv = Game:getPlayer():getInventory()
    for index = 101, 104 do
        local info = inv:getItemStackInfo(index - 1)
        if info.id == 0 then
            GUICustomShop:useBodyPart(map[index - 100], "1")
        end
    end
end

function UICustomShop:onShow()
    if self.curSelectGoods ~= nil then
        if isGameStart then
            self.awPlayer1:reflreshArmor(Game:getPlayer())
            self.awPlayer2:reflreshArmor(Game:getPlayer())
        end
        return
    end
    for pos, item in pairs(self.lvTabs.items) do
        if pos == 1 then
            item:setChecked(true)
            break
        end
    end
    if Game:getPlayer():getSex() == 2 then
        self.awPlayer1:SetActor1("girl.actor", "idle", 0)
        self.awPlayer2:SetActor1("girl.actor", "idle", 0)
    else
        self.awPlayer1:SetActor1("boy.actor", "idle", 0)
        self.awPlayer2:SetActor1("boy.actor", "idle", 0)
    end
    self.awPlayer1:reflreshArmor(Game:getPlayer())
    self.awPlayer2:reflreshArmor(Game:getPlayer())
end

function UICustomShop:initTabs()
    local llTabs = self:getChildWindow("BedWarCustomShop-Tabs")
    self.lvTabs = IGUIListView.new("BedWarCustomShop-Tabs-List", llTabs)
    self.lvTabs:setItemSpace(4)

    local customShop = CustomShopConfig:getCustomShop()
    for _, tabs in pairs(customShop) do
        local tab = GUICustomShopTab.new("BedWarCustomShopTab.json")
        tab:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 64 })
        tab:onDataChanged(tabs.tabs)
        self.lvTabs:addItem(tab)
    end
    customShop = {}
end

local function updateTabsLayout(tabs, tab)
    local itemHeight = tab.root:GetPixelSize().y
    local listHeight = tabs.root:GetPixelSize().y
    tabs.root:SetItemHeight(itemHeight + listHeight + math.random(1, 100))
    local items = tabs.items
    local _tab
    for _, item in pairs(items) do
        if item == tab then
            _tab = tab
        end
    end
    if not _tab then
        return
    end
    itemHeight = _tab.root:GetPixelSize().y
    local itemPosY = _tab.root:GetYPosition()[2]
    listHeight = tabs:getHeight()
    local currentOffset = tabs.root:GetScrollOffset()
    if itemPosY + itemHeight + currentOffset < listHeight and itemPosY >= -currentOffset then
        return
    end
    local container = tabs.root:GetChildByIndex(0)
    local containerHeight = container:GetPixelSize().y
    local maxOffset = listHeight - containerHeight
    local needOffset = itemPosY + currentOffset
    local offset = currentOffset - needOffset
    tabs.root:SetScrollOffset(math.min(math.max(offset, maxOffset), 0))
end

function UICustomShop:onSelectTab(tab)
    self:onSelectSubTab(tab)
    for _, item in pairs(self.lvTabs.items) do
        item:setChecked(item.type == tab.type)
    end
end

function UICustomShop:setSelectTab(tabId)
    for _, item in pairs(self.lvTabs.items) do
        if item.tabId == tabId then
            self:onSelectTab(item)
        end
    end
end

function UICustomShop:updateTabsLayout(tab)
    updateTabsLayout(self.lvTabs, tab)
end

function UICustomShop:showModelType(type)
    if type == CustomShopModelType.Small then
        self.awPlayer1:SetVisible(true)
        self.awPlayer2:SetVisible(false)
        self.llContent:SetBackImage("set:bed_war_custom_shop_bg.json image:bg1")
    else
        self.awPlayer1:SetVisible(false)
        self.awPlayer2:SetVisible(true)
        self.llContent:SetBackImage("set:bed_war_custom_shop_bg.json image:bg2")
    end
end

function UICustomShop:useBodyPart(part, mesh)
    self.awPlayer1:UseBodyPart(part, mesh)
    self.awPlayer2:UseBodyPart(part, mesh)
end

function UICustomShop:playSkill(skill)
    self.awPlayer1:PlaySkill(skill)
    self.awPlayer2:PlaySkill(skill)
end

function UICustomShop:unloadBodyPart(part)
    self.awPlayer1:UnloadBodyPart(part)
    self.awPlayer2:UnloadBodyPart(part)
end

function UICustomShop:onSelectGoods(goods)
    local oldGoods = self.curSelectGoods
    self.curSelectGoods = nil
    self.goodsAdapter:notifyItemDataChange(oldGoods)
    self.curSelectGoods = goods
    self.goodsAdapter:notifyItemDataChange(goods)
    self:updateBuyButtonUI()
    CustomShop:onSelectGoods(self.curSelectGoods)
end

function UICustomShop:updateGoodsLayout(goods)
    for index, _goods in pairs(CustomShopConfig:getGoodsList(goods.TabId)) do
        if _goods.Id == goods.Id then
            self.gvGoodsList:getWidth()
            local height = self.goodsAdapter:getItemHeight()[2]
            local upperHeight = (math.ceil(index / 2) - 1) * (height + 8)
            self.goodsAdapter:setScrollOffset(-upperHeight)
        end
    end
end

function UICustomShop:updateBuyButtonUI()
    if not self.curSelectGoods then
        return
    end
    self.btnBuy:SetVisible(true)
    self.btnBuy:SetNormalImage("set:bed_war_upgrade_store.json image:btn_yellow")
    self.btnBuy:SetPushedImage("set:bed_war_upgrade_store.json image:btn_yellow")
    self.tvNoBuyText:SetVisible(false)
    if self.curSelectGoods.Time == -1 or self.curSelectGoods.Time > 0 then
        if self.curSelectGoods.Status == CustomShopGoodsStatus.Equiped then
            self.btnBuy:SetNormalImage("set:bed_war_upgrade_store.json image:btn_yellow")
            self.btnBuy:SetPushedImage("set:bed_war_upgrade_store.json image:btn_yellow")
            self.btnBuy:SetText(Lang:getString("bed.war.custom.shop.unload"))
            local type = CustomShopConfig:getTabType(tonumber(self.curSelectTab.tabId))
            if type == CustomGoodsType.Action then
                self.btnBuy:SetVisible(false)
                self.tvNoBuyText:SetText(Lang:getString("good.equipped"))
                self.tvNoBuyText:SetVisible(true)
            end
        else
            self.btnBuy:SetText(Lang:getString("bed.war.custom.shop.equip"))
        end
    else
        if self.curSelectGoods.GetWay == 2 then
            self.btnBuy:SetVisible(false)
            self.tvNoBuyText:SetVisible(true)
            self.tvNoBuyText:SetText(Lang:getString("get.by.sum.recharge"))
            return
        elseif self.curSelectGoods.GetWay == 3 then
            self.btnBuy:SetVisible(false)
            self.tvNoBuyText:SetVisible(true)
            self.tvNoBuyText:SetText(Lang:getString("get.by.treasure.challenge"))
            return
        elseif self.curSelectGoods.GetWay == 4 then
            self.btnBuy:SetVisible(false)
            self.tvNoBuyText:SetVisible(true)
            self.tvNoBuyText:SetText(Lang:getString("get.by.license"))
        end

        self.btnBuy:SetText(Lang:getString("shop_btn_buy"))
    end
end

function UICustomShop:onSelectSubTab(tab)
    if self.curSelectTab then
        if self.curSelectTab.tabId == tab.tabId then
            return
        end
        CustomShop:onTabChange(self.curSelectTab, false)
    end
    self:showModelType(CustomShopConfig:getTabModelType(tab.tabId))
    ReportUtil.reportCustomShopPage(tostring(tab.tabId))
    self.curSelectTab = tab
    CustomShop:onTabChange(self.curSelectTab, true)
    local goodsList = CustomShopConfig:getGoodsList(tab.tabId)
    self.goodsAdapter:setData(goodsList)
    if #goodsList > 0 then
        GUICustomShop:onSelectGoods(goodsList[1])
    end
    self.goodsAdapter:setScrollOffset(0)
end

function UICustomShop:updateListUI()
    self.goodsAdapter:notifyDataChange()
    self:updateBuyButtonUI()
end

function UICustomShop:updateGoodsUI(goods)
    self.goodsAdapter:notifyItemDataChange(goods)
end

function UICustomShop:onBuyClick()
    if not self.curSelectGoods then
        return
    end
    if self.curSelectGoods.Time == -1 or self.curSelectGoods.Time > 0 then
        if self.curSelectGoods.Status == CustomShopGoodsStatus.Equiped then
            CustomShop:onUnloadGoods(self.curSelectGoods) --卸下装备
        else
            SoundUtil.playSound(SoundConfig.useGoodsStore)
            CustomShop:onEquipGoods(self.curSelectGoods) --去装备
        end
    else
        ReportUtil.reportCustomShopBuy("button1", self.curSelectGoods.Id)
        SoundUtil.playSound(SoundConfig.buyGoodsStore)
        if self.curSelectGoods.DiscountPrices < 0 then
            return
        end
        GoodsDetailContent:setGoodsInfo(self.curSelectGoods.Image, self.curSelectGoods.Name,
                PayHelper.getMoneyIcon(Define.Money.DIAMOND), self.curSelectGoods.DiscountPrices)
        GoodsDetailContent:hidePriceLayout()
        CustomDialog.builder().setContentView(GoodsDetailContent)
                    .setHideLeftButton()
                    .setTitleText("gui_bird_store_desc")
                    .setRightIcon("set:bed_war_block_shop.json image:icon_cube_border")
                    .setRightText(tostring(self.curSelectGoods.DiscountPrices))
                    .setRightClickListener(function()
            LuaTimer:schedule(function()
                CheckMoneyContent:setTextColor(Color.BLACK)
                PayHelper.checkMoney(Define.Money.DIAMOND, self.curSelectGoods.DiscountPrices, function(canBuy)
                    if canBuy then
                        ReportUtil.reportCustomShopBuy("button2", self.curSelectGoods.Id)
                        CustomShop:onBuyGoods(self.curSelectGoods) --去购买
                    end
                end)
            end, 100)
        end)        .show()
    end
end

function UICustomShop:showBuyGoodsSuccess(goodsId)
    local goods = CustomShopConfig:getGoodsConfig(goodsId)
    if not goods then
        return
    end
    if CustomShopConfig:getGoodsType(goods) == CustomGoodsType.Action then
        CustomShop:onEquipGoods(goods)
        return
    end
    if not GUICustomShop:isShow() then
        return
    end
    GoodsDetailContent:setGoodsInfo(goods.Image, goods.Name, PayHelper.getMoneyIcon(Define.Money.DIAMOND), goods.Price)
    GoodsDetailContent:hidePriceLayout()
    local type = CustomShopConfig:getTabType(tonumber(goods.TabId))
    if type == CustomGoodsType.Action then
        CustomDialog.builder()
                    .setContentView(GoodsDetailContent)
                    .setCloseVisible(false)
                    .setHideLeftButton()
                    .setRightText("custom.shop.equip.immediate")
                    .setRightClickListener(function()
            CustomShop:onEquipGoods(goods)
        end)        .show()
    else
        CustomDialog.builder()
                    .setContentView(GoodsDetailContent)
                    .setHideLeftButton()
                    .setRightText("custom.shop.equip.immediate")
                    .setRightClickListener(function()
            CustomShop:onEquipGoods(goods)
        end)        .show()
    end
end

return UICustomShop

